maxlength="160" placeholder="z. B. REWE"></label><label>Gekauft am<input type="date" name="purchased_at" value="<?=gmdate('Y-m-d')?>"></label></div><div class="check-pair"><label><input type="checkbox" name="favorite" value="1" <?=!empty($entry['favorite'])?'checked':''?>> Favorit</label><label><input type="checkbox" name="movie_night" value="1" <?=!empty($entry['movie_night'])?'checked':''?>> Filmabend</label></div><label>Notiz<textarea name="note" maxlength="3000" rows="4" placeholder="Was soll dein zukünftiges Ich wissen?"><?=e($entry['note']??'')?></textarea></label><label>Eigenes Bewertungsfoto<input type="file" name="review_photo" accept="image/jpeg,image/png,image/webp"></label><button class="button" type="submit"><?= $entry?'Bewertung aktualisieren':'Bewertung speichern' ?></button><p class="sync-note" data-sync-status></p></form></section><aside class="data-sheet"><p class="section-index">Produktdaten</p><?php foreach(['ingredients'=>'Zutaten','allergens'=>'Allergene','traces'=>'Spuren'] as $key=>$label):?><div><h3><?=$label?></h3><p><?=e($product[$key]??'Nicht angegeben')?></p></div><?php endforeach;?><p class="data-warning">Produktdaten können unvollständig sein. Im Zweifel gelten die Angaben auf der Verpackung.</p><?php if(!empty($product['source_url'])):?><a href="<?=e($product['source_url'])?>" rel="noopener noreferrer" target="_blank">Quelle bei Open Food Facts ↗</a><?php endif;?></aside></div>
